#!/usr/bin/env python3
from __future__ import annotations

import argparse
import json
import os
import subprocess
import sys
from pathlib import Path
from typing import Any


DIRTY_BUCKETS = [
    "taskScoped",
    "preExistingUnrelated",
    "adjacentFollowup",
    "generatedOrCache",
    "sensitiveOrConfig",
    "unknown",
]

RESIDUAL_BUCKETS = [bucket for bucket in DIRTY_BUCKETS if bucket != "taskScoped"]

RESIDUAL_ACTION_FIELDS = ("paths", "action", "rationale", "nextStep")

RUNTIME_PATTERNS = (
    "/src/mcp/",
    "/src/rpc/",
    "/server.",
    "/mcp/",
    "/mcps/",
    "/hooks/",
    "/launchd/",
    "/LaunchAgents/",
    "/dot_codex/",
